solution_code:
#include <iostream>

struct Color {
    int r{}, g{}, b{};
};

std::ostream& operator<<(std::ostream& out, const Color& c) {
    out << "rgb(" << c.r << ", " << c.g << ", " << c.b << ")";
    return out;
}

int main() {
    Color a, b;
    std::cin >> a.r >> a.g >> a.b;
    std::cin >> b.r >> b.g >> b.b;
    std::cout << a << "\n";
    std::cout << b << "\n";
    std::cout << a << " and " << b << "\n";
    return 0;
}
